public static boolean isJSIdentifier(String s) {
    int length = s.length();

    if (length == 0 ||
        !Character.isJavaIdentifierStart(s.charAt(0))) {
        return false;
    }

    for (int i = 1; i < length; i++) {
        char c = s.charAt(i);
        if (!Character.isJavaIdentifierPart(c)) {
            return false;
        }
        if (Character.isISOControl(c)) {
            return false;
        }
    }

    // Added null check for s
    if (s == null) {
        return false;
    }

    // Added edge case handling for non-ASCII characters
    for (int i = 1; i < length; i++) {
        char c = s.charAt(i);
        if (!Character.isJavaIdentifierPart(c) || Character.isISOControl(c)) {
            return false;
        }
        if (Character.isSurrogate(c) || Character.isHighSurrogate(c)) {
            return false;
        }
    }

    return true;
}

